/**
 * ThematiqueBadges — pictos thématiques extraits pixel-perfect du WP vegourmet.fr
 * (thème « Yummy Bites » / WP Delicious).
 *
 * Chaque picto = cercle coloré + path blanc, exactement comme sur le WP.
 * Sources SVG vérifiées sur :
 *   - vegourmet.fr/recette-thematique/sans-soja/        → soy-free (#ee9060)
 *   - vegourmet.fr/recette-type/plat-vegan/             → quick-meals (#e6b170), cold (#73d4ef), gluten-free (#F7BD31)
 *   - vegourmet.fr/recettes/salade-cesar-vegan-*        → confirmé froid + repas-rapide
 *   - vegourmet.fr/recettes/gratin-de-chou-fleur-vegan* → confirmé repas-rapide + sans-gluten
 */
import type { ReactNode } from "react";

interface ThematiqueBadgesProps {
  /** Slugs recette-thematique (depuis frontmatter.taxonomies["recette-thematique"]). */
  slugs: string[];
  /** Taille du picto en px (défaut : 38). */
  size?: number;
  /** Classe CSS appliquée au conteneur. */
  className?: string;
  /** Slug à exclure de l'affichage (taxonomie active de la page courante). */
  excludeSlug?: string;
}

interface BadgeConfig {
  label: string;
  /** Composant SVG inline (JSX pur, pas de dangerouslySetInnerHTML). */
  Icon: (props: { size: number }) => ReactNode;
}

