/**
 * Mapping slug → config picto.
 * Un slug absent du mapping est simplement ignoré (pas de crash).
 */
const BADGE_MAP: Record<string, BadgeConfig> = {
  "repas-rapide": { label: "Repas rapide", Icon: QuickMealsIcon },
  "froid":        { label: "Froid",        Icon: FroidIcon },
  "sans-gluten":  { label: "Sans gluten",  Icon: SansGlutenIcon },
  "sans-soja":    { label: "Sans soja",    Icon: SansSojaIcon },
};

/**
 * Affiche les pictos thématiques WP (multi-badges) pour une recette.
 * Seuls les slugs présents dans BADGE_MAP sont rendus (ordre stable).
 */
export function ThematiqueBadges({
  slugs,
  size = 38,
  className = "",
  excludeSlug,
}: ThematiqueBadgesProps) {
  const known = slugs.filter((s) => s in BADGE_MAP && s !== excludeSlug);
  if (known.length === 0) return null;

  return (
    <span className={`vg-thematique-badges${className ? ` ${className}` : ""}`}>
      {known.map((slug) => {
        const cfg = BADGE_MAP[slug];
        return (
          <span
            key={slug}
            className="vg-thematique-badge dr-svg-icon"
            title={cfg.label}
            aria-label={cfg.label}
          >
            <cfg.Icon size={size} />
          </span>
        );
      })}
    </span>
  );
}
